import type { HTMLArkProps } from '@ark-ui/react/factory';
import type { ComponentProps, ComponentRef } from 'react';
import { Accordion as AccordionPrimitive, useAccordion } from '@ark-ui/react/accordion';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { PlusIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Accordion.module.css';

const AccordionRoot = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Root>,
  ComponentProps<typeof AccordionPrimitive.Root>
>(function AccordionRoot({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.Root
      ref={ref}
      data-slot="accordion-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const AccordionRootProvider = forwardRef<
  ComponentRef<typeof AccordionPrimitive.RootProvider>,
  ComponentProps<typeof AccordionPrimitive.RootProvider>
>(function AccordionRootProvider({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.RootProvider
      ref={ref}
      data-slot="accordion-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const AccordionItem = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Item>,
  ComponentProps<typeof AccordionPrimitive.Item>
>(function AccordionItem({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.Item
      ref={ref}
      data-slot="accordion-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const AccordionItemTrigger = forwardRef<
  ComponentRef<typeof AccordionPrimitive.ItemTrigger>,
  ComponentProps<typeof AccordionPrimitive.ItemTrigger>
>(function AccordionItemTrigger({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.ItemTrigger
      ref={ref}
      data-slot="accordion-item-trigger"
      className={clsx(styles.itemTrigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const AccordionItemIndicator = forwardRef<
  ComponentRef<typeof AccordionPrimitive.ItemIndicator>,
  ComponentProps<typeof AccordionPrimitive.ItemIndicator>
>(function AccordionItemIndicator({ className, children, ...props }, ref) {
  return (
    <AccordionPrimitive.ItemIndicator
      ref={ref}
      data-slot="accordion-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <PlusIcon />}
    </AccordionPrimitive.ItemIndicator>
  );
});

const AccordionItemContent = forwardRef<
  ComponentRef<typeof AccordionPrimitive.ItemContent>,
  ComponentProps<typeof AccordionPrimitive.ItemContent>
>(function AccordionItemContent({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.ItemContent
      ref={ref}
      data-slot="accordion-item-content"
      className={clsx(styles.itemContent, normalizeClassName(className))}
      {...props}
    />
  );
});

const AccordionItemBody = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AccordionItemBody({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="accordion"
        data-part="item-body"
        data-slot="accordion-item-body"
        className={clsx(styles.itemBody, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const Accordion = Object.assign(AccordionRoot, {
  Root: AccordionRoot,
  RootProvider: AccordionRootProvider,
  Item: AccordionItem,
  ItemTrigger: AccordionItemTrigger,
  ItemIndicator: AccordionItemIndicator,
  ItemContent: AccordionItemContent,
  ItemBody: AccordionItemBody,
});

export { Accordion, useAccordion };

@layer ui.components {
  @keyframes accordion-item-content-open {
    from {
      height: 0;
      opacity: var(--accordion-item-content-closed-opacity, 0.01);
    }

    to {
      height: var(--height);
      opacity: var(--accordion-item-content-open-opacity, 1);
    }
  }

  @keyframes accordion-item-content-closed {
    from {
      height: var(--height);
      opacity: var(--accordion-item-content-open-opacity, 1);
    }

    to {
      height: 0;
      opacity: var(--accordion-item-content-closed-opacity, 0.01);
    }
  }

  @keyframes accordion-item-content-open-horizontal {
    from {
      width: 0;
      opacity: var(--accordion-item-content-closed-opacity, 0.01);
    }

    to {
      width: var(--width);
      opacity: var(--accordion-item-content-open-opacity, 1);
    }
  }

  @keyframes accordion-item-content-closed-horizontal {
    from {
      width: var(--width);
      opacity: var(--accordion-item-content-open-opacity, 1);
    }

    to {
      width: 0;
      opacity: var(--accordion-item-content-closed-opacity, 0.01);
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--accordion-width, 100%);
    max-width: var(--accordion-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    color: var(--accordion-color, var(--color-foreground));

    &[data-orientation='horizontal'] {
      width: var(--accordion-horizontal-width, auto);
      height: var(--accordion-horizontal-height, 20rem);
      max-height: var(--accordion-horizontal-max-height, 100%);
      flex-direction: row;
    }
  }

  .item {
    overflow-anchor: none;

    &[data-orientation='vertical']:not(:last-child) {
      border-bottom: var(--accordion-item-border-width, var(--border-width-sm)) solid
        var(--accordion-item-border-color, var(--color-border));
    }

    &[data-orientation='horizontal'] {
      display: flex;

      &:not(:last-child) {
        border-inline-end: var(--accordion-item-border-width, var(--border-width-sm)) solid
          var(--accordion-item-border-color, var(--color-border));
      }
    }
  }

  .itemTrigger {
    box-sizing: border-box;
    display: flex;
    width: 100%;
    align-items: center;
    justify-content: space-between;
    gap: var(--accordion-trigger-gap, var(--spacing-4));
    margin: 0;
    padding-block: var(--accordion-trigger-padding-y, var(--spacing-2));
    padding-inline: var(--accordion-trigger-padding-x, var(--spacing-3));
    border: 0;
    background-color: var(--accordion-trigger-bg, var(--color-muted));
    color: inherit;
    font: inherit;
    font-size: var(--accordion-trigger-font-size, var(--text-md));
    line-height: var(--accordion-trigger-line-height, var(--line-height-text-md));
    text-align: left;
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--accordion-trigger-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      position: relative;
      z-index: 1;
      outline: var(--accordion-focus-ring-width, var(--border-width-md)) solid
        var(--accordion-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--accordion-focus-ring-offset, var(--border-width-sm)) * -1);
    }

    &:is([disabled], [data-disabled]) {
      cursor: default;
      opacity: var(--accordion-disabled-opacity, var(--opacity-disabled));
    }

    &[data-orientation='horizontal'] {
      width: var(--accordion-horizontal-trigger-width, 2.5rem);
      height: 100%;
      justify-content: center;
      writing-mode: sideways-lr;
    }
  }

  .itemIndicator {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--accordion-icon-size, 0.75rem);
    height: var(--accordion-icon-size, 0.75rem);
    flex-shrink: 0;
    transition: transform var(--accordion-icon-transition, var(--transition-default));

    & svg {
      width: 100%;
      height: 100%;
    }

    &[data-state='open'] {
      transform: var(--accordion-icon-open-transform, rotate(45deg) scale(1.1));
    }
  }

  .itemContent {
    box-sizing: border-box;
    overflow: hidden;
    color: var(--accordion-item-content-color, var(--color-muted-foreground));
    font-size: var(--accordion-item-content-font-size, var(--text-md));
    line-height: var(--accordion-item-content-line-height, var(--line-height-text-md));

    &[hidden]:not([hidden='until-found']) {
      display: none;
    }

    &[data-state='open'][data-orientation='vertical'] {
      animation: accordion-item-content-open
        var(--accordion-item-content-transition, var(--transition-default));
    }

    &[data-state='closed'][data-orientation='vertical'] {
      animation: accordion-item-content-closed
        var(--accordion-item-content-transition, var(--transition-default));
    }

    &[data-state='open'][data-orientation='horizontal'] {
      animation: accordion-item-content-open-horizontal
        var(--accordion-item-content-transition, var(--transition-default));
    }

    &[data-state='closed'][data-orientation='horizontal'] {
      animation: accordion-item-content-closed-horizontal
        var(--accordion-item-content-transition, var(--transition-default));
    }

    &[data-orientation='horizontal'] > * {
      width: var(--accordion-horizontal-content-width, 16rem);
    }
  }

  .itemBody {
    display: grid;
    gap: var(--accordion-item-body-gap, var(--spacing-3));
    min-width: 0;
    padding: var(--accordion-item-body-padding, var(--spacing-3));
  }
}
